        {pct = 65, msg = "Đang liên kết API Blox Fruits nâng cao..."},
        {pct = 85, msg = "Đang nạp 12 Module Script Premium..."},
        {pct = 100, msg = "Tải dữ liệu hoàn tất! Đang mở menu..."}
    }
    for _, p in ipairs(phases) do
        L_Status.Text = p.msg .. " (" .. p.pct .. "%)"
        TweenService:Create(L_BarFill, TweenInfo.new(0.4, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
            Size = UDim2.new(p.pct / 100, 0, 1, 0)
        }):Play()
        task.wait(0.4)
    end
    task.wait(0.2)
    local fade = TweenService:Create(LoadingFrame, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {
        Size = UDim2.new(0, 400, 0, 0),
        Position = UDim2.new(0.5, -200, 0.5, 0)
    })
    fade:Play()
    fade.Completed:Wait()
    LoadingGui:Destroy()
end)

