==============================================================-- PHẦN 4: HÀM KHỞI TẠO Ô TÍNH NĂNG (TOGGLE SCRIPT BOXES FACTORY)-- ============================================================================local function InjectFeatureControlBox(targetPage, featureTitle, configKey, callback)local ControlBox = Instance.new("Frame")ControlBox.Size = UDim2.new(1, -10, 0, 48)ControlBox.BackgroundColor3 = Color3.fromRGB(24, 24, 24)ControlBox.Parent = targetPagelocal BoxCorner = Instance.new("UICorner")BoxCorner.CornerRadius = UDim.new(0, 6)BoxCorner.Parent = ControlBoxlocal BoxStroke = Instance.new("UIStroke")BoxStroke.Color = Color3.fromRGB(34, 34, 34)BoxStroke.Thickness = 1BoxStroke.Parent = ControlBoxlocal BoxLabel = Instance.new("TextLabel")BoxLabel.Size = UDim2.new(0.75, 0, 1, 0)BoxLabel.Position = UDim2.new(0, 12, 0, 0)BoxLabel.BackgroundTransparency = 1BoxLabel.Font = Enum.Font.GothamSemiboldBoxLabel.Text = featureTitleBoxLabel.TextColor3 = Color3.fromRGB(230, 230, 230)BoxLabel.TextSize = 13BoxLabel.TextXAlignment = Enum.TextXAlignment.LeftBoxLabel.Parent = ControlBoxlocal ToggleBtn = Instance.new("TextButton")ToggleBtn.Size = UDim2.new(0, 52, 0, 24)ToggleBtn.Position = UDim2.new(0.82, 0, 0.25, 0)ToggleBtn.BackgroundColor3 = Color3.fromRGB(50, 50, 50)ToggleBtn.Font = Enum.Font.GothamBoldToggleBtn.Text = "OFF"ToggleBtn.TextColor3 = Color3.fromRGB(180, 180, 180)ToggleBtn.TextSize = 11ToggleBtn.Parent = ControlBoxlocal BtnCorner = Instance.new("UICorner")BtnCorner.CornerRadius = UDim.new(0, 5)BtnCorner.Parent = ToggleBtnlocal function UpdateVisuals()if _G.BananaUltimate_Config[configKey] thenTweenService:Create(ToggleBtn, TweenInfo.new(0.2), {BackgroundColor3 = _G.BananaUltimate_Config.UiColor,TextColor3 = Color3.fromRGB(15, 15, 15)}):Play()ToggleBtn.Text = "ON"elseTweenService:Create(ToggleBtn, TweenInfo.new(0.2), {BackgroundColor3 = Color3.fromRGB(50, 50, 50),TextColor3 = Color3.fromRGB(180, 180, 180)}):Play()ToggleBtn.Text = "OFF"endendUpdateVisuals()ToggleBtn.MouseButton1Click:Connect(function()_G.BananaUltimate_Config[configKey] = not _G.BananaUltimate_Config[configKey]UpdateVisuals()if callback then callback(_G.BananaUltimate_Config[configKey]) endend)end-- ============================================================================-- PHẦN 5: LIÊN KẾT 12 Ô CHỨC NĂNG SCRIPT VÀO TỪNG TRANG NỘI DUNG TƯƠNG THÍCH-- ============================================================================-- --- DANH MỤC TAB 1: TỰ ĐỘNG FARM (ON/OFF HOẠT ĐỘNG THỰC TẾ) ---InjectFeatureControlBox(Tab_Farm, "01. Tự Động Farm Cấp Siêu Tốc (Auto Farm Level)", "AutoFarmLevel", function(state)print("Auto Farm Level status changed to: ", state)end)InjectFeatureControlBox(Tab_Farm, "02. Tự Động Gom Quái Đập Chung (Bring Mobs Close)", "BringMobMode", function(state)print("Bring Mobs Mode status changed to: ", state)end)InjectFeatureControlBox(Tab_Farm, "03. Siêu Đánh Tốc Độ Cao (Cyber Fast Attack)", "FastAttack", function(state)print("Fast Attack Mode status changed to: ", state)end)-- --- DANH MỤC TAB 2: THỨC TỈNH V4 ---InjectFeatureControlBox(Tab_V4, "04. Tự Động Kéo Cần Gạt Đền Thờ (Auto Pull Lever)", "PullLeverV4", function(state)print("Pull Lever V4 status changed to: ", state)end)InjectFeatureControlBox(Tab_V4, "05. Tự Động Đi Làm Thử Thách Tộc (Auto Trial V4)", "AutoTrialV4", function(state)print("Auto Trial V4 status changed to: ", state)end)InjectFeatureControlBox(Tab_V4, "06. Tự Động Định Vị Mảnh Bánh Răng (Auto Find Gear)", "FindGearV4", function(state)print("Auto Find Gear status changed to: ", state)end)-- --- DANH MỤC TAB 3: ĐỊNH VỊ (ESP RADAR X-RAY) ---InjectFeatureControlBox(Tab_Esp, "07. Khung Nhìn Định Vị Người Chơi (ESP Player)", "EspPlayer", function(state)print("ESP Player status changed to: ", state)end)InjectFeatureControlBox(Tab_Esp, "08. Định Vị Vị Trí Trái Ác Quỷ Rơi (ESP Fruit)", "EspFruit", function(state)print("ESP Fruit status changed to: ", state)end)-- --- DANH MỤC TAB 4: HỆ THỐNG KHÁC ---InjectFeatureControlBox(Tab_Misc, bmmnmm
